    }
    
    static let shared = SecureDataModule()
    
    private let keychainHelper = KeychainHelper.shared
    
    // IV size for AES CBC
    private let ivSize = kCCBlockSizeAES128 // 16 bytes
    // HMAC-SHA256 output size
    private let hmacSize = Int(CC_SHA256_DIGEST_LENGTH) // 32 bytes
    
    private init() {}
    
    // MARK: - Core Encrypt / Decrypt (AES-256-CBC + HMAC-SHA256 for Encrypt-then-MAC)
    
    /// Encrypted format: [IV (16 bytes)] [Ciphertext (variable)] [HMAC-SHA256 (32 bytes)]
    func encrypt(data: Data) throws -> Data {
        let key = try keychainHelper.getOrCreateEncryptionKey()
        
        // Generate cryptographically secure random IV
        var iv = Data(count: ivSize)
        let ivResult = iv.withUnsafeMutableBytes { buffer in
            SecRandomCopyBytes(kSecRandomDefault, ivSize, buffer.baseAddress!)
        }
        guard ivResult == errSecSuccess else {
            throw EncryptionError.ivGenerationFailed
        }
        
        // AES-256-CBC encryption with PKCS7 padding
        let bufferSize = data.count + kCCBlockSizeAES128
        var encryptedData = Data(count: bufferSize)
        var numBytesEncrypted: size_t = 0
        
        let cryptStatus = key.withUnsafeBytes { keyBytes in
            iv.withUnsafeBytes { ivBytes in
                data.withUnsafeBytes { dataBytes in
                    encryptedData.withUnsafeMutableBytes { encryptedBytes in
                        CCCrypt(
                            CCOperation(kCCEncrypt),
                            CCAlgorithm(kCCAlgorithmAES),
                            CCOptions(kCCOptionPKCS7Padding),
                            keyBytes.baseAddress, kCCKeySizeAES256,
                            ivBytes.baseAddress,
                            dataBytes.baseAddress, data.count,
                            encryptedBytes.baseAddress, bufferSize,
                            &numBytesEncrypted
                        )
                    }
                }
            }
        }
        
        guard cryptStatus == kCCSuccess else {
            throw EncryptionError.encryptionFailed(status: cryptStatus)
        }
        
        encryptedData.removeSubrange(numBytesEncrypted..<encryptedData.count)
        
        // Construct: IV + Ciphertext
        var result = Data()
        result.append(iv)
        result.append(encryptedData)
        
        // Compute HMAC-SHA256 over (IV + Ciphertext) using the same key
        // In production, consider using a separate HMAC key derived via HKDF
        let hmac = computeHMAC(data: result, key: key)
        result.append(hmac)
        
        return result
    }
    
    func decrypt(data: Data) throws -> Data {
        let key = try keychainHelper.getOrCreateEncryptionKey()
        
        // Minimum size: IV + at least 1 block + HMAC
        let minimumSize = ivSize + kCCBlockSizeAES128 + hmacSize
        guard data.count >= minimumSize else {
            throw EncryptionError.invalidEncryptedDataFormat
        }
        
        // Split components
        let ivAndCiphertext = data.prefix(data.count - hmacSize)
        let receivedHMAC = data.suffix(hmacSize)
        
        // Verify HMAC first (Encrypt-then-MAC: verify before decrypting)
        let computedHMAC = computeHMAC(data: ivAndCiphertext, key: key)
        guard constantTimeCompare(computedHMAC, Data(receivedHMAC)) else {
            throw EncryptionError.hmacVerificationFailed
        }
        
        let iv = ivAndCiphertext.prefix(ivSize)
        let ciphertext = ivAndCiphertext.dropFirst(ivSize)
        
        let bufferSize = ciphertext.count + kCCBlockSizeAES128
        var decryptedData = Data(count: bufferSize)
        var numBytesDecrypted: size_t = 0
        
        let cryptStatus = key.withUnsafeBytes { keyBytes in
            iv.withUnsafeBytes { ivBytes in
                ciphertext.withUnsafeBytes { cipherBytes in
                    decryptedData.withUnsafeMutableBytes { decryptedBytes in
                        CCCrypt(
                            CCOperation(kCCDecrypt),
                            CCAlgorithm(kCCAlgorithmAES),
                            CCOptions(kCCOptionPKCS7Padding),
                            keyBytes.baseAddress, kCCKeySizeAES256,
                            ivBytes.baseAddress,
                            cipherBytes.baseAddress, ciphertext.count,
                            decryptedBytes.baseAddress, bufferSize,
                            &numBytesDecrypted
                        )
                    }
                }
            }
        }
        
        guard cryptStatus == kCCSuccess else {
            throw EncryptionError.decryptionFailed(status: cryptStatus)
        }
        
        decryptedData.removeSubrange(numBytesDecrypted..<decryptedData.count)
        return decryptedData
    }
    
    // MARK: - HMAC Computation
    
    private func computeHMAC(data: Data, key: Data) -> Data {
        var hmac = Data(count: hmacSize)
        hmac.withUnsafeMutableBytes { hmacBytes in
            data.withUnsafeBytes { dataBytes in
                key.withUnsafeBytes { keyBytes in
                    CCHmac(
                        CCHmacAlgorithm(kCCHmacAlgSHA256),
                        keyBytes.baseAddress, key.count,
                        dataBytes.baseAddress, data.count,
                        hmacBytes.baseAddress
                    )
                }
            }
        }
        return hmac
