// MARK: - Secure Local Storage Manager

final class SecureStorageManager {
    
    static let shared = SecureStorageManager()
    
    private let fileManager = FileManager.default
    private let storageDirectory: URL
    
    private init() {
        let documentsPath = fileManager.urls(for: .applicationSupportDirectory, in: .userDomainMask).first!
        storageDirectory = documentsPath.appendingPathComponent("SecureStorage", isDirectory: true)
        
        if !fileManager.fileExists(atPath: storageDirectory.path) {
            try? fileManager.createDirectory(at: storageDirectory, withIntermediateDirectories: true)
        }
        
        // Exclude from backups to prevent sensitive data leaking to iCloud/iTunes
        var resourceValues = URLResourceValues()
        resourceValues.isExcludedFromBackup = true
        var mutableURL = storageDirectory
        try? mutableURL.setResourceValues(resourceValues)
    }
    
    func store(data: Data, forKey key: String) throws {
        let encryptedData = try SecureDataModule.shared.encrypt(data: data)
        let fileURL = storageDirectory.appendingPathComponent(key.sha256Hash)
        try encryptedData.write(to: fileURL, options: [.atomic, .completeFileProtection])
    }
    
    func retrieve(forKey key: String) throws -> Data {
        let fileURL = storageDirectory.appendingPathComponent(key.sha256Hash)
        let encryptedData = try Data(contentsOf: fileURL)
        return try SecureDataModule.shared.decrypt(data: encryptedData)
    }
    
    func storeString(_ string: String, forKey key: String) throws {
        guard let data = string.data(using: .utf8) else {
            throw SecureDataModule.EncryptionError.dataConversionFailed
        }
        try store(data: data, forKey: key)
    }
    
    func retrieveString(forKey key: String) throws -> String {
        let data = try retrieve(forKey: key)
        guard let string = String(data: data, encoding: .utf8) else {
            throw SecureDataModule.EncryptionError.dataConversionFailed
        }
        return string
    }
    
    func delete(forKey key: String) throws {
        let fileURL = storageDirectory.appendingPathComponent(key.sha256Hash)
        if fileManager.fileExists(atPath: fileURL.path) {
            try fileManager.removeItem(at: fileURL)
        }
    }
    
    func deleteAll() throws {
        if fileManager.fileExists(atPath: storageDirectory.path) {
            let contents = try fileManager.contentsOfDirectory(at: storageDirectory, includingPropertiesForKeys: nil)
            for fileURL in contents {
                try fileManager.removeItem(at: fileURL)
            }
        }
    }
}

// MARK: - String Hashing Extension (for storage key obfuscation)

extension String {
    var sha256Hash: String {
        guard let data = self.data(using: .utf8) else { return self }
        var hash = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        data.withUnsafeBytes { buffer in
            _ = CC_SHA256(buffer.baseAddress, CC_LONG(data.count), &hash)
        }
        return hash.map { String(format: "%02x", $0) }.joined()
    }
}